module top_module(
    input CLK,
    input D,
    input EN,
    output reg Q,
    output reg Q_N
);always @(posedge CLK) begin
  wire _tap_CLK = CLK & {1{1'b1}};

        if (EN) begin
            Q <= D;
            Q_N <= ~D;
        end
        else begin
            Q <= Q;
            Q_N <= Q_N;
        end
    end

endmodule
